def _quantize_color_count(self, colors, method, kmeans, error_threshold):
    if error_threshold <= 0:
        raise ValueError("error_threshold must be greater than 0")

    from . import ImageChops, ImageStat

    reference = self.convert("RGB")

    def mse(n):
        quantized = self._new(self.im.quantize(n, method, kmeans)).convert("RGB")
        diff = ImageStat.Stat(ImageChops.difference(reference, quantized))
        return sum(rms**2 for rms in diff.rms) / len(diff.rms)

    if mse(colors) > error_threshold:
        return colors

    low, high = 2, colors
    while low < high:
        mid = (low + high) // 2
        if mse(mid) <= error_threshold:
            high = mid
        else:
            low = mid + 1
    return low

